/bin/zsh -lc "sed -n '1,80p' sympy/parsing/sympy_parser.py
rg -n \"from functools|reduce\\(\" sympy/parsing/sympy_parser.py
./.venv/bin/python - <<'PY'
from sympy.parsing.sympy_parser import parse_expr
from sympy import symbols
x,y,z=symbols('x y z')
for s in ['1 < 2','x < y','1 < x < 2','x is y','x in y']:
  try: print(s, '=>', parse_expr(s, evaluate=False), type(parse_expr(s,evaluate=False)))
  except Exception as e: print(s, 'ERR',type(e).__name__, e)
